// OmniProject broker binding (the contract is docs/BROKER-HTTP-BINDING.md).
const body = msg.payload || {};
const action = body.action;

// 1) verify handshake — answer WITHOUT calling a backend.
if (body.verify === true) {
    msg.statusCode = 200;
    msg.payload = { success: true, data: { verified: true } };
    return msg;
}

// 2) capabilities — declare which data domains your backend can feed.
if (action === 'get_capabilities') {
    msg.statusCode = 200;
    msg.payload = { success: true, data: { issues: true, scheduling: true, resources: true, financials: true, portfolio: true, history: true, raid: true } };
    return msg;
}

// 3) data actions — wire these to your backend with an HTTP Request node, then
//    normalise the result to { success: true, data: <result> }. Until then, report
//    them honestly as unimplemented (a 501, not a silent empty success).
msg.statusCode = 501;
msg.payload = { success: false, message: 'action "' + action + '" not wired — add an HTTP Request node to your backend (see node-red-flow.md)' };
return msg;
